-- Hyprland-run windowrule
hl.window_rule({
    name  = "move-hyprland-run",
    match = { class = "hyprland-run" },

    move  = "20 monitor_h-120",
    float = true,
})

-- Прозрачность терминалов
hl.window_rule({
    name = "ghostty-opacity",
    match = { class = "com.mitchellh.ghostty" },
    opacity = "0.90 0.90",
})
hl.window_rule({
    name = "wezterm-opacity",
    match = { class = "org.wezfurlong.wezterm" },
    opacity = "0.92 0.92",
})

-- Плавающие окна
hl.window_rule({
    name = "pavucontrol-float",
    match = { class = "org.pulseaudio.pavucontrol" },
    float = true,
    size = "800 600",
    center = true,
})
hl.window_rule({
    name = "nm-connection-editor-float",
    match = { class = "nm-connection-editor" },
    float = true,
})
hl.window_rule({
    name = "calculator-float",
    match = { class = "org.gnome.Calculator" },
    float = true,
})
hl.window_rule({
    name = "amneziavpn-float",
    match = { class = "AmneziaVPN" },
    float = true,
})

-- Thunderbird
hl.window_rule({
    name = "thunderbird-float",
    match = { class = "thunderbird_thunderbird" },
    float = true,
    size = "1300 950",
    center = true,
    opacity = "0.95 0.95",
})
